SELECT mem_total, swap_total
FROM monitoring_logs
WHERE server_id = 0 AND timestamp > '2022-12-31';

SELECT server_name, ip_address, location
FROM servers
WHERE location = 'New York';

SELECT COUNT(DISTINCT server_id) AS total_servers
FROM servers
WHERE last_reboot > datetime('now', '-30 day');

SELECT server_id, COUNT(task_id) AS task_count
FROM scheduled_tasks
GROUP BY server_id;

SELECT s.*, u.*
FROM servers s
JOIN user_access_logs u ON s.server_id = u.user_id;

SELECT COUNT(alert_id) AS total_alerts
FROM alerts
WHERE alert_time >= '2022-01-01 00:00:00' AND alert_time < '2022-01-02 00:00:00';

SELECT server_id, SUM(disk_read_bytes) AS total_disk_read, SUM(disk_write_bytes) AS total_disk_write
FROM monitoring_logs
GROUP BY server_id;
